  "total_matches": 12,
  "capabilities": [
    {
      "name": "find_problematic_files",
      "summary": "Finds files with names that break ShareSync: colons, asterisks, question marks, pipes, angle brackets, conflict suffixes, and extremely long names. Returns exact paths that can be fixed with rename_file_to_old or remove_invalid_chars.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        }
      ],
      "optional_args": [
        {
          "name": "filter",
          "type": "string",
          "description": "Search term, file path, or folder name depending on the tool."
        }
      ],
      "example_call": {
        "name": "find_problematic_files",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1"
        }
      }
    },
    {
      "name": "inspect_path_metadata",
      "summary": "Shows POSIX metadata for an exact filesystem path: owner, group, permissions, size, inode, link count, and timestamps. Required first step before any permission or ACL forensics. Requires exact_path.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [],
      "example_call": {
        "name": "inspect_path_metadata",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "inspect_path_acl",
      "summary": "Shows the POSIX and Synology ACL entries for an exact filesystem path. Reveals which users and groups have explicit ACL permissions beyond standard POSIX mode. Requires exact_path.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [],
      "example_call": {
        "name": "inspect_path_acl",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "inspect_effective_permissions",
      "summary": "Shows the effective access on a path: POSIX mode, ACL entries, and optionally the group memberships and share-level access for a specific user. Requires exact_path. Pass a username in filter to check user-specific access.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": false
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [
        {
          "name": "filter",
          "type": "string",
          "description": "Search term, file path, or folder name depending on the tool."
        }
      ],
      "example_call": {
        "name": "inspect_effective_permissions",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "find_recent_path_changes",
      "summary": "Finds files recently modified under an exact path using mtime. Shows files changed within lookback_hours (default 2h) with timestamps and owner. Requires exact_path.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [
        {
          "name": "lookback_hours",
          "type": "number",
          "description": "How many hours of logs to look back. Default: 2.",
          "default": 2
        }
      ],
      "example_call": {
        "name": "find_recent_path_changes",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "live_file_search",
      "summary": "Strict live filesystem search by filename glob, with no indexing, no fuzzy matching, and no content search. Use when Universal Search or Windows Search ignore filters or return too much noise. Examples: name_pattern='*pattern*.xls*', root_path='/volume1/Share'. Returns matching paths with type, size, mtime, owner, and group.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "name_pattern",
          "type": "string",
          "description": "Strict filename glob to match against basenames only, e.g. '*budget*.xls*'. This is not fuzzy search and does not search file contents."
        }
      ],
      "optional_args": [
        {
          "name": "root_path",
          "type": "string",
          "description": "Absolute directory to search. Leave empty to search all mounted /volumeN data volumes.",
          "default": ""
        },
        {
          "name": "entry_type",
          "type": "file | directory | any",
          "description": "Limit matches by filesystem entry type. Default: file.",
          "default": "file"
        },
        {
          "name": "case_sensitive",
          "type": "boolean",
          "description": "Use case-sensitive glob matching by default. Set false to use find -iname.",
          "default": true
        },
        {
          "name": "max_depth",
          "type": "number",
          "description": "Maximum directory depth below root_path. 0 means unlimited. Clamped to [0, 30].",
          "default": 0
        },
        {
          "name": "max_results",
          "type": "number",
          "description": "Maximum matches to print. Default 500, clamped to [1, 2000].",
          "default": 500
        },
        {
          "name": "include_synology_metadata",
          "type": "boolean",
          "description": "Include @eaDir and .SynologyWorkingDirectory metadata trees. Default false.",
          "default": false
        }
      ],
      "example_call": {
        "name": "live_file_search",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "name_pattern": "<name_pattern>"
        }
      }
    },
    {
      "name": "find_path_versions_and_snapshots",
      "summary": "Looks for recoverable versions of a path: Btrfs snapshots under @Recently-Snapshot, recycle bin entries, and any Drive version hints in logs. Requires exact_path pointing to a file or directory.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [],
      "example_call": {
        "name": "find_path_versions_and_snapshots",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "search_file_access_audit",
      "summary": "Searches DSM file access audit logs for a path fragment or username. Pass the search term in filter. Use to investigate who accessed or modified a file. Requires DSM file access logging to be enabled.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        }
      ],
      "optional_args": [
        {
          "name": "lookback_hours",
          "type": "number",
          "description": "How many hours of logs to look back. Default: 2.",
          "default": 2
        },
        {
          "name": "filter",
          "type": "string",
          "description": "Search term, file path, or folder name depending on the tool."
        }
      ],
      "example_call": {
        "name": "search_file_access_audit",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1"
        }
      }
    },
    {
      "name": "search_file_access_log",
      "summary": "Queries the DSM Log Center file access audit via the WebAPI (SYNO.Core.Log.Center) for a given path fragment, action, or date range. Returns the raw JSON response with newest events first. Requires Log Center package installed and 'Log Sending → Local' file-access logging enabled in DSM Control Panel. Optional filters: path_filter (client-side grep on the JSON), date_from/date_to (ISO yyyy-mm-dd), action_filter (delete|write|read|rename), limit (default 100, max 1000).",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        }
      ],
      "optional_args": [
        {
          "name": "path_filter",
          "type": "string",
          "description": "Substring to grep for in the result set, e.g. a filename or folder fragment."
        },
        {
          "name": "date_from",
          "type": "string",
          "description": "Lower bound ISO date yyyy-mm-dd. Converted to a unix timestamp for the API."
        },
        {
          "name": "date_to",
          "type": "string",
          "description": "Upper bound ISO date yyyy-mm-dd. Converted to a unix timestamp for the API."
        },
        {
          "name": "action_filter",
          "type": "delete | write | read | rename",
          "description": "Restrict to a single action. Applied client-side on the JSON response."
        },
        {
          "name": "limit",
          "type": "number",
          "description": "Max records to fetch from the API. Default 100, clamped to [1, 1000].",
          "default": 100
        }
      ],
      "example_call": {
        "name": "search_file_access_log",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1"
        }
      }
    },
    {
      "name": "search_smb_path_activity",
      "summary": "Searches Samba/SMB logs for activity related to a path fragment, share name, or username. Use to investigate who accessed, created, or deleted files over SMB. Pass the search term in filter.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        }
      ],
      "optional_args": [
        {
          "name": "lookback_hours",
          "type": "number",
          "description": "How many hours of logs to look back. Default: 2.",
          "default": 2
        },
        {
          "name": "filter",
          "type": "string",
          "description": "Search term, file path, or folder name depending on the tool."
        }
      ],
      "example_call": {
        "name": "search_smb_path_activity",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1"
        }
      }
    },
    {
      "name": "hash_file",
      "summary": "Computes SHA-256 and MD5 hashes for an exact file path, along with size and timestamps. Use to verify file integrity, detect silent corruption, or confirm whether two copies are identical. Requires exact_path.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [],
      "example_call": {
        "name": "hash_file",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    },
    {
      "name": "compare_file_versions",
      "summary": "Compares two file paths: size, mtime, owner, mode, and SHA-256 hashes side by side. Optionally shows a text diff for small text files. Provide first path in exact_path and second path in filter.",
      "group": "files",
      "safety": {
        "classification": "read_only",
        "read_only": true,
        "state_changing": false,
        "destructive": false,
        "preview_supported": false,
        "requires_confirmation": false,
        "reversible": true
      },
      "required_args": [
        {
          "name": "target",
          "type": "edgesynology1 | edgesynology2 | both",
          "description": "Which NAS to run on. Use 'both' to query both simultaneously."
        },
        {
          "name": "exact_path",
          "type": "string",
          "description": "Exact absolute filesystem path to inspect (e.g. /volume1/data/folder/file.txt)."
        }
      ],
      "optional_args": [
        {
          "name": "filter",
          "type": "string",
          "description": "Search term, file path, or folder name depending on the tool."
        }
      ],
      "example_call": {
        "name": "compare_file_versions",
        "target": "edgesynology1",
        "args": {
          "target": "edgesynology1",
          "exact_path": "<exact_path>"
        }
      }
    }
  ],
  "boundaries": [
    "No arbitrary write shell access through run_command; NAS API blocks write commands there.",
    "Named write tools preview first and require args.confirmed=true to execute.",
    "Targets are edgesynology1, edgesynology2, or both.",
    "Kubernetes operations are not available."
  ]
}

