def sqlite(db, sql, output=False, line=False, header=False):
    if not os.path.isfile(db):
        raise RuntimeError("File not found " + db)

    cmd = ['sqlite3']
    if line:
        cmd.append('-line')
    elif header:
        cmd.append('-header')

    cmd += [db, sql]

    if output:
        subprocess.call(cmd)
    else:
        return subprocess.check_output(cmd).decode("utf8").rstrip()

