const outputPath = path.join(outputDir, "edgesynology1_sfconflict_review.xlsx");

const text = await fs.readFile(inputPath, "utf8");
const rows = text
  .split(/\r?\n/)
  .filter(Boolean)
  .map((line) => JSON.parse(line));

rows.sort((a, b) => {
  const pa = a.project_cluster.localeCompare(b.project_cluster);
  if (pa !== 0) return pa;
  return a.conflict_path.localeCompare(b.conflict_path);
});

function groupBy(items, keyFn) {
  const map = new Map();
  for (const item of items) {
    const key = keyFn(item) || "(blank)";
    const agg = map.get(key) || {
      key,
      files: 0,
      conflictBytes: 0,
      originalMissing: 0,
      different: 0,
      same: 0,
      hashErrors: 0,
    };
    agg.files += 1;
    agg.conflictBytes += item.conflict_size_bytes || 0;
    if (!item.original_exists) agg.originalMissing += 1;
    if (item.hash_status === "different") agg.different += 1;
    if (item.hash_status === "same") agg.same += 1;
    if (String(item.hash_status).startsWith("hash_error")) agg.hashErrors += 1;
    map.set(key, agg);
  }
  return [...map.values()]
    .sort((a, b) => b.files - a.files || b.conflictBytes - a.conflictBytes)
    .map((r) => [
      r.key,
      r.files,
      +(r.conflictBytes / 1024 / 1024 / 1024).toFixed(2),
      r.different,
      r.same,
      r.originalMissing,
      r.hashErrors,
    ]);
}

const totalBytes = rows.reduce((sum, r) => sum + (r.conflict_size_bytes || 0), 0);
const summaryRows = [
  ["Metric", "Value"],
  ["Live conflict files in report", rows.length],
  ["Total conflict size GiB", +(totalBytes / 1024 / 1024 / 1024).toFixed(2)],
  ["Hash different from original", rows.filter((r) => r.hash_status === "different").length],
  ["Hash same as original", rows.filter((r) => r.hash_status === "same").length],
  ["Original missing", rows.filter((r) => !r.original_exists).length],
  ["Conflict identity", rows[0]?.conflict_identity || ""],
  ["NAS root scanned", "/volume1/mac/Decor"],
  ["Generated from", "edgesynology1 read-only filesystem scan"],
];

const reviewHeaders = [
  "project_cluster",
  "filename",
  "extension",
  "conflict_owner",
  "conflict_group",
  "hash_status",
  "original_exists",
  "conflict_size_mib",
  "original_size_mib",
  "conflict_mtime",
  "conflict_ctime",
  "original_mtime",
  "original_owner",
  "conflict_stamp_utc_text",
  "conflict_identity",
  "conflict_path",
  "original_path",
  "conflict_sha256",
  "original_sha256",
];

const reviewValues = [
  reviewHeaders,
  ...rows.map((r) => reviewHeaders.map((h) => r[h] ?? "")),
];

const projectSummary = [
  ["Project cluster", "Files", "Conflict GiB", "Different", "Same", "Original missing", "Hash errors"],
  ...groupBy(rows, (r) => r.project_cluster),
];
const ownerSummary = [
  ["Conflict owner", "Files", "Conflict GiB", "Different", "Same", "Original missing", "Hash errors"],
  ...groupBy(rows, (r) => r.conflict_owner),
];
const extensionSummary = [
  ["Extension", "Files", "Conflict GiB", "Different", "Same", "Original missing", "Hash errors"],
  ...groupBy(rows, (r) => r.extension),
];
const statusSummary = [
  ["Hash status", "Files", "Conflict GiB", "Different", "Same", "Original missing", "Hash errors"],
  ...groupBy(rows, (r) => r.hash_status),
];

const workbook = Workbook.create();
const summary = workbook.worksheets.add("Summary");
const review = workbook.worksheets.add("Review");
const projects = workbook.worksheets.add("Projects");
const owners = workbook.worksheets.add("Owners");
const extensions = workbook.worksheets.add("Extensions");
const statuses = workbook.worksheets.add("Hash Status");

function writeTable(sheet, startCell, values, tableName) {
  const rowCount = values.length;
  const colCount = values[0].length;
  const range = sheet.getRange(startCell).resize(rowCount, colCount);
  range.values = values;
  range.format.borders = { preset: "all", style: "thin", color: "#D9E2EC" };
  const header = range.getRow(0);
  header.format = {
    fill: "#1F4E78",
    font: { bold: true, color: "#FFFFFF" },
  };
  const table = sheet.tables.add(range.address, true, tableName);
  table.showBandedRows = true;
  table.showFilterButton = true;
  return range;
}

summary.getRange("A1:D1").merge();
summary.getRange("A1").values = [["edgesynology1 SFConflict Review"]];
summary.getRange("A1").format = {
  font: { bold: true, size: 16, color: "#17324D" },
};
writeTable(summary, "A3", summaryRows, "SummaryTable");
writeTable(summary, "D3", projectSummary.slice(0, 11), "TopProjectsTable");
writeTable(summary, "D17", ownerSummary.slice(0, 12), "TopOwnersTable");

writeTable(review, "A1", reviewValues, "ConflictReview");
writeTable(projects, "A1", projectSummary, "ProjectSummary");
writeTable(owners, "A1", ownerSummary, "OwnerSummary");
writeTable(extensions, "A1", extensionSummary, "ExtensionSummary");
writeTable(statuses, "A1", statusSummary, "HashStatusSummary");

for (const sheet of [summary, review, projects, owners, extensions, statuses]) {
  sheet.freezePanes.freezeRows(1);
  sheet.showGridLines = false;
  const used = sheet.getUsedRange();
  used.format.autofitColumns();
  used.format.autofitRows();
}

summary.freezePanes.freezeRows(2);
review.freezePanes.freezeRows(1);
review.getRange("P:Q").format.columnWidthPx = 520;
review.getRange("R:S").format.columnWidthPx = 210;
review.getRange("A:A").format.columnWidthPx = 320;
review.getRange("B:B").format.columnWidthPx = 260;
review.getRange("F:F").format.columnWidthPx = 120;
summary.getRange("A:A").format.columnWidthPx = 240;
summary.getRange("D:D").format.columnWidthPx = 360;

const topProjectChart = summary.charts.add("bar", summary.getRange("D3:F11"));
topProjectChart.title = "Top Conflict Clusters";
topProjectChart.hasLegend = true;
topProjectChart.setPosition("L3", "S20");

const ownerChart = summary.charts.add("bar", summary.getRange("D17:F27"));
ownerChart.title = "Top Owners";
ownerChart.hasLegend = true;
ownerChart.setPosition("L22", "S39");

const errors = await workbook.inspect({
  kind: "match",
  searchTerm: "#REF!|#DIV/0!|#VALUE!|#NAME\\?|#N/A",
  options: { useRegex: true, maxResults: 50 },
  summary: "formula error scan",
});
console.log(errors.ndjson);

await fs.mkdir(outputDir, { recursive: true });
await workbook.render({ sheetName: "Summary", autoCrop: "all", scale: 1, format: "png" });
await workbook.render({ sheetName: "Review", range: "A1:I20", scale: 1, format: "png" });
const xlsx = await SpreadsheetFile.exportXlsx(workbook);
await xlsx.save(outputPath);
console.log(outputPath);
